INSERT INTO `chat_messages` VALUES (1,'thông tin truyện Thuần Thú Sư Thiên Tài','2026-03-31 07:59:17.000000','user',2),(2,'Truyện \"Thuần Thú Sư Thiên Tài\" thuộc thể loại Action. Tác giả là Thành Phong và đang được cập nhật với số lượt xem là 67,656. Bạn có quan tâm đến các truyện liên quan như \"Tiểu Thư Nhỏ Vô Năng Muốn Cứu Rỗi Gia Tộc\", \"Tôi Có Thể Nhìn Thấy Tiêu Đề\" hoặc \"Hầm Ngục Thơm Mùi Gà Rán\"?','2026-03-31 07:59:39.000000','assistant',2),(3,'thông tin về Thanh Gươm Diệt Quỷ (Truyện Màu)','2026-03-31 10:32:10.000000','user',3),(4,'Thanh Gươm Diệt Quỷ (Truyện Màu) là một truyện thuộc thể loại **Action**. Tác giả là TruyenQQ và đã hoàn thành. Nó có 67,667 lượt xem.','2026-03-31 10:33:01.000000','assistant',3),(5,'mua premium','2026-03-31 10:33:30.000000','user',3),(6,'Đối với truyện \"Thanh Gươm Diệt Quyết\" thuộc thể loại Action, bạn có các tùy chọn gói Premium sau:\n\n1. **Gói Linh Thạch**: \n   - Giá: 19,000 VNĐ\n   - Thời hạn: 7 ngày\n   - Uu đãi: Đọc các chương Premium cơ bản và không có quảng cáo trong 7 ngày.\n\n2. **Gói Trúc Cơ**:\n   - Giá: 59,000 VNĐ\n   - Thời hạn: 30 ngày\n   - Uu đãi: Mở khóa toàn bộ kho truyện VIP và ưu tiên cập nhật chương mới nhất trong 30 ngày.\n\n3. **Gói Tiên Tôn**:\n   - Giá: 149,000 VNĐ\n   - Thời hạn: 90 ngày\n   - Uu đãi: Đặc quyền tối thượng: Đọc mọi thể loại, hỗ trợ đọc offline và có huy hiệu King độc quyền trong 90 ngày.\n\nBạn có muốn biết thêm thông tin về các gói Premium hay chỉ cần lựa chọn gói phù hợp?','2026-03-31 10:34:27.000000','assistant',3),(7,'chaof','2026-04-01 07:57:10.000000','user',1),(8,'Xin chào! Hệ thống Nhom8 Story hiện chưa cập nhật dữ liệu về tác giả có tên \"chaof\". Bạn vui lòng thử tìm ở các mục khác hoặc xem trực tiếp trên website để có thông tin chính xác nhất.','2026-04-01 07:57:47.000000','assistant',1),(9,'Chứng Minh Phẩm Giá thông tin về truyện này','2026-04-06 14:45:52.000000','user',1),(10,'Chứng Minh Phẩm Giá là một truyện tranh thuộc thể loại Action, được tác giả Bdcomics viết. Truyện đã hoàn thành và đã có 76,766 lượt xem.\n\nTrên hệ thống Nhom8 Story hiện chưa có thông tin về giá tiền hoặc gói premium cho truyện này. Bạn có thể đọc trực tiếp trên website để theo dõi quá trình cập nhật nhé!','2026-04-06 14:46:47.000000','assistant',1),(11,'tư vấn về premium','2026-04-06 16:11:44.000000','user',3),(12,'Dựa vào thông tin bạn cung cấp, tôi có thể tư vấn cho bạn về các gói Premium. \n\nTruyện \"Thanh Gươm Diệt Quyết\" thuộc thể loại Action do tác giả TruyenQQ viết. Hiện tại bạn có 3 gói lựa chọn Premium như sau:\n\n- **Gói Linh Thạch**:\n  - Giá: 19,000 VNĐ\n  - Thời hạn: 7 ngày\n  - Uu đãi: Đọc các chương Premium cơ bản và không quảng cáo trong 7 ngày.\n\n- **Gói Trúc Cơ**:\n  - Giá: 59,000 VNĐ\n  - Thời hạn: 30 ngày\n  - Uu đãi: Mở khóa toàn bộ kho truyện VIP và ưu tiên cập nhật chương mới nhất trong 30 ngày.\n\n- **Gói Tiên Tôn**:\n  - Giá: 149,000 VNĐ\n  - Thời hạn: 90 ngày\n  - Uu đãi: Đặc quyền tối thượng: Đọc mọi thể loại, hỗ trợ đọc offline và có huy hiệu King độc quyền trong 90 ngày.\n\nNếu bạn muốn đọc truyện này với ưu đãi hàng đầu thì nên chọn Gói Tiên Tôn vì có thời hạn lâu hơn và nhiều quyền lợi hơn. Còn nếu chỉ cần đọc truyện một cách thoải mái trong vòng 7 hoặc 30 ngày, bạn cũng có thể cân nhắc các gói khác phù hợp với ngân sách của mình.\n\nBạn muốn biết thêm thông tin về bất kỳ gói nào không?','2026-04-06 16:13:59.000000','assistant',3),(13,'Chứng Minh Phẩm Giá  thông tin truyện','2026-04-06 16:22:29.000000','user',3),(14,'Dựa vào dữ liệu từ hệ thống, đây là thông tin về truyện \"Chứng Minh Phẩm Giá\":\n\n- Tên truyện: Chứng Minh Phẩm Giá  \n- Tác giả: Bdcomics  \n- Thể loại: Action  \n- Trạng thái: COMPLETED (đã hoàn thành)  \n- Lượt xem: 76,766  \n\nTruyện thuộc thể loại Action và đã hoàn thành. Đây là một truyện có lượt xem tương đối cao trong hệ thống của chúng tôi.','2026-04-06 16:24:21.000000','assistant',3);
/*!40000 ALTER TABLE `chat_messages` ENABLE KEYS */;
