INSERT INTO `faq_items` VALUES (1,_binary '','Chào bạn! Mình đang hỗ trợ CSKH đây. Bạn cần hỗ trợ về thanh toán, Premium, hướng dẫn sử dụng hay báo lỗi ạ?',100,'xin chao|chao ban|hello|hi'),(2,_binary '','Bạn có thể vào trang Premium để xem gói và thanh toán. Sau khi thanh toán thành công, hệ thống sẽ tự cập nhật quyền Premium cho tài khoản của bạn.',90,'premium|goi premium|mua premium|nang cap premium'),(3,_binary '','Hiện tại hệ thống hỗ trợ thanh toán trực tuyến cho gói Premium. Nếu thanh toán xong mà chưa nhận gói, bạn hãy gửi mã giao dịch để admin kiểm tra giúp nhé.',80,'thanh toan|payment|nap tien|mua goi'),(4,_binary '','Bạn chỉ cần đăng nhập, chọn truyện muốn đọc và mở chương tương ứng. Nếu muốn lưu truyện hoặc dùng Premium, hãy đăng nhập trước khi thao tác nhé.',70,'huong dan|huong dan su dung|cach su dung|doc truyen'),(5,_binary '','Bạn vui lòng mô tả lỗi đang gặp, kèm ảnh chụp màn hình nếu có. Admin sẽ kiểm tra và phản hồi cho bạn sớm nhất.',60,'bao loi|loi he thong|bug|khong vao duoc');
/*!40000 ALTER TABLE `faq_items` ENABLE KEYS */;
UNLOCK TABLES;

