INSERT INTO `stories` VALUES (6,'Bdcomics','https://img.otruyenapi.com/uploads/comics/vi-du-that-bai-cua-loi-nguyen-hoan-hao-thumb.jpg','2026-03-06 09:17:06.000000','Truyện tranh Ví Dụ Thất Bại Của Lời Nguyền Hoàn Hảo được cập nhật nhanh và đầy đủ nhất tại TruyenQQ. Bạn đọc đừng quên để lại bình luận và chia sẻ, ủng hộ TruyenQQ ra các chương mới nhất của truyện Ví Dụ Thất Bại Của Lời Nguyền Hoàn Hảo.',_binary '\0','ONGOING','Ví Dụ Thất Bại Của Lời Nguyền Hoàn Hảo','2026-03-12 15:47:31.000000',53445,2,'vi-du-that-bai-cua-loi-nguyen-hoan-hao',_binary '\0'),(7,'Kishitani Todoroki, Uratani Nagi','https://img.otruyenapi.com/uploads/comics/r15-ja-dame-desuka-thumb.jpg','2026-03-06 10:07:38.000000','\"Mình sẽ làm gì để trở thành người lớn?\" Akane Amou, lớn lên trong sự bảo bọc nghiêm khắc của cha mẹ mà không tiếp xúc với phương tiện giải trí, bước qua tuổi 15, trước những thứ \"tình cảm\", thậm chí là một nụ hôn cũng không thể xem được. Giờ đã vào trường cấp ba, cùng với cậu bạn Fuyumine, Amou sẽ bước qua những rào cản ấy. Liệu cô bé có thể xem được một phim nhán mác \"cấm trẻ em\"? (Truyện dành cho lứa tuổi 16+)',_binary '\0','ONGOING','R15+ Ja Dame Desuka?','2026-03-06 10:07:38.000000',4354,2,'r15-ja-dame-desuka',_binary '\0'),(8,'Kishitani Todoroki, Uratani Nagi','https://img.otruyenapi.com/uploads/comics/xem-phim-nguoi-lon-duoc-khong-thumb.jpg','2026-03-06 10:07:39.000000','(Truyện dành cho lứa tuổi 16+)\"Mình sẽ làm gì để trở thành người lớn?\" Akane Amou, lớn lên trong sự bảo bọc nghiêm khắc của cha mẹ mà không tiếp xúc với phương tiện giải trí, bước qua tuổi 15, trước những thứ \"tình cảm\", thậm chí là một nụ hôn cũng không thể xem được. Giờ đã vào trường cấp ba, cùng với cậu bạn Fuyumine, Amou sẽ bước qua những rào cản ấy. Liệu cô bé có thể xem được một phim nhán mác \"cấm trẻ em\"?',_binary '\0','ONGOING','Xem Phim','2026-03-06 10:07:39.000000',54335,2,'xem-phim-nguoi-lon-duoc-khong',_binary '\0'),(9,'','https://img.otruyenapi.com/uploads/comics/wizards-soul-koi-no-seisen-thumb.jpg','2026-03-06 10:08:01.000000','Truyện tranh Wizard\'s Soul ~Koi No Seisen~ được cập nhật nhanh và đầy đủ nhất tại TruyenQQ. Bạn đọc đừng quên để lại bình luận và chia sẻ, ủng hộ TruyenQQ ra các chương mới nhất của truyện Wizard\'s Soul ~Koi No Seisen~.',_binary '\0','ONGOING','Wizard\'s Soul ~Koi No Seisen~','2026-03-06 10:08:01.000000',765,2,'wizards-soul-koi-no-seisen',_binary '\0'),(10,'','https://img.otruyenapi.com/uploads/comics/tro-thanh-vo-dich-bang-he-thong-giam-gia-tri-thumb.jpg','2026-03-06 10:08:17.000000','Truyện tranh Trở Thành Vô Địch Bằng Hệ Thống Giảm Giá Trị được cập nhật nhanh và đầy đủ nhất tại . Bạn đọc đừng quên để lại bình luận và chia sẻ, ủng hộ ra các chương mới nhất của truyện Trở Thành Vô Địch Bằng Hệ Thống Giảm Giá Trị.',_binary '\0','ONGOING','Trở Thành Vô Địch Bằng Hệ Thống Giảm Giá Trị','2026-03-06 10:08:17.000000',54654,2,'tro-thanh-vo-dich-bang-he-thong-giam-gia-tri',_binary '\0'),(11,'Đang cập nhật','https://img.otruyenapi.com/uploads/comics/toi-da-giet-tuyen-thu-hoc-vien-thumb.jpg','2026-03-06 10:08:31.000000','Truyện tranh Tôi Đã Giết Tuyển Thủ Học Viện được cập nhật nhanh và đầy đủ nhất tại . Bạn đọc đừng quên để lại bình luận và chia sẻ, ủng hộ ra các chương mới nhất của truyện Tôi Đã Giết Tuyển Thủ Học Viện.',_binary '\0','ONGOING','Tôi Đã Giết Tuyển Thủ Học Viện','2026-03-06 10:08:31.000000',12324,2,'toi-da-giet-tuyen-thu-hoc-vien',_binary '\0'),(12,'Đang cập nhật','https://img.otruyenapi.com/uploads/comics/song-chung-voi-dai-ty-ma-ca-rong-thumb.jpg','2026-03-06 10:08:50.000000','(Phúc Hắc cường thế mỹ diễm hấp huyết quỷ tỷ tỷ &gt; ngọt ngào cứng cỏi tài mê nữ sinh viên) Ngày Tống Dụ chuyển vào nhà mới, bị trong viện kỳ quái đá điêu nhảy ra từ mỹ diễm hấp huyết quỷ tỷ tỷ cắn. Veriel bị lực lượng không biết trên người Tống Dụ đánh thức, khát vọng đối với bản năng máu làm cho nàng cắn Tống Dụ, cũng dùng kim tệ hấp dẫn Tống Dụ, để Tống Dụ lưu lại làm việc cho nàng. Hai người bắt đầu cuộc sống chung không vừa mắt.',_binary '\0','COMPLETED','Sống Chung Với Đại Tỷ Ma Cà Rồng','2026-03-06 10:08:50.000000',43223,2,'song-chung-voi-dai-ty-ma-ca-rong',_binary '\0'),(13,'Đang cập nhật','https://img.otruyenapi.com/uploads/comics/tro-thanh-co-chau-gai-bi-khinh-miet-cua-gia-toc-vo-lam-thumb.jpg','2026-03-06 10:09:37.000000','Cô xuyên không trở thành một nhân vật chính trong thế giới võ lâm. Cô trở thành BaekRi Yeon, đứa con gái ngốc nghếch và quậy phá của BaekRi Eui Kang, một người thầy chân chính và là người đã dẫn dắt nhân vật nam chính trở thành một anh hùng. Sau khi bất ngờ bị giết, cô mở mắt ra và trở thành một đứa trẻ có thể làm đảo ngược mọi thứ. ‘Mình, lần này có thể nhận được sự yêu thương không?” Ở kiếp này, cô có niềm tin rằng mình sẽ trở thành con gái được yêu thương chứ không phải đứa con gái chịu nhiều tổn thương nữa, cô bắt đầu cuộc sống được mọi người kính trọng từ cháu gái của gia đình Baekri. Những gia tộc cản trở xuất hiện trước mặt Yeon, người chỉ muốn đi trên con đường rải đẩy hoa, và Baek Ri Pae-hyeok, là tộc trưởng và cũng là ông nội của cô, ông sở hữu khí phách của một vị vua, người có thể khiến cả núi sông và cây cối rung chuyển chỉ bằng một ánh mắt. “Ngươi cho rằng ngươi đáng giá như thế sao!” “Vâng!” Ông không thể che giấu sự hốt hoảng trước khí thế mạnh mẽ của cháu gái “Nếu còn một tia hy vọng mong manh, người làm cha sao con có thể từ bỏ?” “…Như là một đứa trẻ cứng đầu.” Ông lão bắt đầu mềm lòng vì hai cha con tuyệt mỹ đánh bại với quyết tâm sẽ cứu đứa cháu gái không có tài nghệ võ công … Tôi nghĩ rằng được sống ở thời điểm này là xứng đáng, nhưng nỗi ám ảnh của các ứng cử viên nam chính đột nhiên bắt đầu? Yeoni của chúng ta, bây giờ hãy chỉ đi trên con đường hoa thôi nhé!',_binary '\0','COMPLETED','Trở Thành Cô Cháu Gái Bị Khinh Miệt Của Gia Tộc Võ Lâm','2026-03-06 10:09:37.000000',3429,2,'tro-thanh-co-chau-gai-bi-khinh-miet-cua-gia-toc-vo-lam',_binary '\0'),(14,'旷盛动漫','https://img.otruyenapi.com/uploads/comics/nhan-mon-bat-tri-dao-thumb.jpg','2026-03-06 10:10:02.000000','Có những khúc quanh trong sự bình thường, có niềm vui trong nguy hiểm, và thế giới ngoài nhận thức của con người là điều mà con người chưa biết đến. Hãy cầm điện thoại và theo chân bậc thầy bắt quái vật Chuyi và \"người mới\" Sanxian để khám phá những điều kỳ diệu chưa biết. Những bí mật chưa biết đang chờ bạn ở đây. [Liên hệ hợp tác kinh doanh QQ: 1371665284]Bởi vì toàn bộ thành phố đều là phiền toái, người già cũng rất bận rộn, bọn họ cũng rất',_binary '\0','COMPLETED','Nhân Môn Bất Tri Đạo','2026-03-06 10:10:02.000000',9675,2,'nhan-mon-bat-tri-dao',_binary '\0'),(15,'','https://img.otruyenapi.com/uploads/comics/mot-ngay-no-toi-bong-thanh-nang-cong-chua-thumb.jpg','2026-03-06 10:10:25.000000','Một ngày nọ, khi tôi mở mắt ra, tôi đã thấy mình trở thành công chúa. Tôi thật là may mắn vì ngay từ khi sinh ra đã ngậm “chiếc thìa vàng”. Nhưng sau đó, tôi đã chết trong tay của cha mình. Hoàng đế Claude – là một người máu lạnh và không có nước mắt .',_binary '\0','COMPLETED','Một Ngày Nọ Tôi Bỗng Thành Nàng Công Chúa','2026-03-06 10:10:25.000000',5466,2,'mot-ngay-no-toi-bong-thanh-nang-cong-chua',_binary '\0'),(16,'Đang cập nhật','https://img.otruyenapi.com/uploads/comics/dai-lao-nao-cung-tranh-sung-ta-thumb.jpg','2026-03-06 10:10:39.000000','Lam Cận sau 3 năm xuyên không trở về, phát hiện thanh danh của chính mình đã bị làm cho tổn hại. Cô chẳng những có thêm 5 vị hôn phu, mà còn có thêm 5 đứa con trai của sủng mẫu cuồng ma từ tiểu thế giới xuyên tới? Bị gọi là phế vật túi rác, cô ấy vẫn dửng dưng bất động, nhưng hết lần này tới lần khác các đại lão đều tranh sủng cô ấy phải làm sao bây giờ?',_binary '\0','COMPLETED','Đại Lão Nào Cũng Tranh Sủng Ta','2026-03-06 10:10:39.000000',9755,2,'dai-lao-nao-cung-tranh-sung-ta',_binary '\0'),(17,'Đang cập nhật','https://img.otruyenapi.com/uploads/comics/chiec-tui-bi-mat-cua-tieu-thu-xau-xi-thumb.jpg','2026-03-06 10:10:54.000000','19 Giam cầm tắm máu vàng do nữ chính sở hữu! Để tồn tại, bạn phải che đi vẻ đẹp này bằng lớp trang điểm xấu xí này!! Bị chiếm hữu bởi nữ anh hùng Lila trong một nơi giam cầm thiếu thốn Chuyên gia trang điểm Yoon Seol thoát khỏi ‘Merry Bed Ending’ Cô che giấu vẻ đẹp của mình bằng lớp trang điểm xấu xí này. Mười năm sau, anh đã tránh được con đường ban đầu. Anh nhận được lời cầu hôn bất ngờ từ Công tước Lucas xấu xí… Liệu cô ấy có một kết thúc có hậu?',_binary '\0','COMPLETED','Chiếc Túi Bí Mật Của Tiểu Thư Xấu Xí','2026-03-06 10:10:54.000000',435,2,'chiec-tui-bi-mat-cua-tieu-thu-xau-xi',_binary '\0'),(18,'','https://img.otruyenapi.com/uploads/comics/tien-hoa-vo-han-bat-dau-tu-con-so-khong-thumb.jpg','2026-03-06 10:11:11.000000','Truyện tranh Tiến Hóa Vô Hạn Bắt Đầu Từ Con Số Không được cập nhật nhanh và đầy đủ nhất tại TruyenQQ. Bạn đọc đừng quên để lại bình luận và chia sẻ, ủng hộ TruyenQQ ra các chương mới nhất của truyện Tiến Hóa Vô Hạn Bắt Đầu Từ Con Số Không.',_binary '\0','ONGOING','Tiến Hóa Vô Hạn Bắt Đầu Từ Con Số Không','2026-03-06 10:11:11.000000',978,2,'tien-hoa-vo-han-bat-dau-tu-con-so-khong',_binary '\0'),(19,'TruyenQQ','https://img.otruyenapi.com/uploads/comics/tieu-thu-nho-vo-nang-muon-cuu-roi-gia-toc-thumb.jpg','2026-03-06 10:11:23.000000','Tiểu Thư Nhỏ Vô Năng Muốn Cứu Rỗi Gia Tộc - Tiểu Thư Nhỏ Vô Năng Muốn Cứu Rỗi Gia Tộc',_binary '\0','COMPLETED','Tiểu Thư Nhỏ Vô Năng Muốn Cứu Rỗi Gia Tộc','2026-03-06 10:11:23.000000',4566,2,'tieu-thu-nho-vo-nang-muon-cuu-roi-gia-toc',_binary '\0'),(20,'TruyenQQ','https://img.otruyenapi.com/uploads/comics/thanh-guom-diet-quy-truyen-mau-thumb.jpg','2026-03-06 10:11:35.000000','Thanh Gươm Diệt Quỷ (Truyện Màu) - Thanh Gươm Diệt Quỷ (truyện Màu)',_binary '\0','COMPLETED','Thanh Gươm Diệt Quỷ (Truyện Màu)','2026-03-06 10:11:35.000000',67667,2,'thanh-guom-diet-quy-truyen-mau',_binary '\0'),(21,'斩魔, Mộng Tiên Giới','https://img.otruyenapi.com/uploads/comics/thuong-nhan-buon-lau-thoi-mat-the-ta-dung-que-cay-doi-vang-thoi-thumb.jpg','2026-03-06 10:11:47.000000','Thương Nhân Buôn Lậu Thời Mạt Thế: Ta Dùng Que Cay Đổi Vàng Thỏi - ',_binary '\0','COMPLETED','Thương Nhân Buôn Lậu Thời Mạt Thế: Ta Dùng Que Cay Đổi Vàng Thỏi','2026-03-06 10:11:47.000000',654,2,'thuong-nhan-buon-lau-thoi-mat-the-ta-dung-que-cay-doi-vang-thoi',_binary '\0'),(22,'TruyenQQ','https://img.otruyenapi.com/uploads/comics/ke-phan-dien-ma-toi-giet-da-song-lai-thumb.jpg','2026-03-06 10:12:00.000000','Kẻ Phản Diện Mà Tôi Giết Đã Sống Lại - Kẻ Phản Diện Mà Tôi Giết Đã Sống Lại',_binary '\0','COMPLETED','Kẻ Phản Diện Mà Tôi Giết Đã Sống Lại','2026-03-06 10:12:00.000000',4564,2,'ke-phan-dien-ma-toi-giet-da-song-lai',_binary '\0'),(23,'Bdcomics','https://img.otruyenapi.com/uploads/comics/ham-nguc-thom-mui-ga-ran-thumb.jpg','2026-03-06 10:13:12.000000','Hầm Ngục Thơm Mùi Gà Rán - ',_binary '\0','COMPLETED','Hầm Ngục Thơm Mùi Gà Rán','2026-03-06 10:13:12.000000',5677,2,'ham-nguc-thom-mui-ga-ran',_binary '\0'),(24,'Bdcomics','https://img.otruyenapi.com/uploads/comics/cong-chua-di-hoc-thumb.jpg','2026-03-06 10:13:59.000000','Công Chúa Đi Học - ',_binary '\0','COMPLETED','Công Chúa Đi Học','2026-03-06 10:13:59.000000',5343,2,'cong-chua-di-hoc',_binary '\0'),(25,'Rei','https://img.otruyenapi.com/uploads/comics/imouto-no-tomodachi-ga-nani-kangae-teru-no-ka-wakaranai-thumb.jpg','2026-03-06 10:14:11.000000','Tập hợp các mẩu truyện ngắn 4 trang do astirt Rayrei vẽ. Câu chuyện kể về cô bé Tsuyu đã crush ông anh trai của cô bạn thân',_binary '','COMPLETED','Imouto no Tomodachi ga Nani Kangae Teru no ka Wakaranai','2026-03-12 17:37:27.000000',534354,2,'imouto-no-tomodachi-ga-nani-kangae-teru-no-ka-wakaranai',_binary '\0'),(26,'Bdcomics','https://img.otruyenapi.com/uploads/comics/chung-minh-pham-gia-thumb.jpg','2026-03-06 10:14:27.000000','Chứng Minh Phẩm Giá - ',_binary '','COMPLETED','Chứng Minh Phẩm Giá','2026-03-12 17:02:00.000000',76766,2,'chung-minh-pham-gia',_binary '\0'),(27,'Bdcomics','https://img.otruyenapi.com/uploads/comics/toi-co-the-nhin-thay-tieu-de-thumb.jpg','2026-03-06 10:19:11.000000','Tôi Có Thể Nhìn Thấy Tiêu Đề - ',_binary '','COMPLETED','Tôi Có Thể Nhìn Thấy Tiêu Đề','2026-03-12 16:54:37.000000',65767,2,'toi-co-the-nhin-thay-tieu-de',_binary '\0'),(28,'Thành Phong','https://img.otruyenapi.com/uploads/comics/thuan-thu-su-thien-tai-thumb.jpg','2026-03-06 10:24:02.000000','Truyện tranh Thuần Thú Sư Thiên Tài được cập nhật nhanh và đầy đủ nhất tại . Bạn đọc đừng quên để lại bình luận và chia sẻ, ủng hộ ra các chương mới nhất của truyện Thuần Thú Sư Thiên Tài.',_binary '','ONGOING','Thuần Thú Sư Thiên Tài','2026-03-12 15:58:57.000000',67656,2,'thuan-thu-su-thien-tai',_binary '\0'),(31,'Đang cập nhật','https://img.otruyenapi.com/uploads/comics/giet-chet-ac-nu-phan-dien-thumb.jpg','2026-03-31 08:19:01.000000','Tôi xuyên vào cơ thể của một nhân vật phản diện tên Eris trong cuốn tiểu thuyết. Cô ta đã tự đầu độc bản thân khi vị hôn thê của cô, một hoàng tử, kết hôn với người bạn từ thời thơ ấu của mình, hầu gái Helena. Từ khoảnh khắc tôi nhận ra mình đang ở trong cuốn tiểu thuyết, mục đích duy nhất của tôi là thoát khỏi cuốn tiểu thuyết này. Cho dù là phải chết, tôi đã cố gắng để thoát khỏi đây, nhưng không thể. Thế nhưng, những chàng trai đã từng ngược đãi và phớt lờ Eris trong kịch bản gốc của tiểu thuyết, nay đã quỳ xuống để cầu xin sự quan tâm và tình cảm từ cô. “Cô là ai?” Là câu hỏi của vị linh mục đã hồi sinh Helena. “Cô...có thật sự là Eris không?” Ngay cả người chiến binh một lòng trung thành với Helena cũng hỏi thế. “Em thay đổi rồi”, đó là câu nói duy nhất hoàng thái tử có thể dùng để miêu tả về Eris. Nó thật lạ lẫm. Bọn họ chưa bao giờ quan tâm đến Eris, và bây giờ lại làm vậy. “Cho dù là thời gian đã trôi qua, ta vẫn không muốn nhận được sự quan tâm của bọn họ”. Cô đã thật sự mất đi niềm tin với tình yêu trong cuộc đời này',_binary '','COMPLETED','Giết Chết Ác Nữ Phản Diện','2026-04-06 16:09:23.000000',0,2,'giet-chet-ac-nu-phan-dien',_binary '\0');
